function ref(category, title, difficulty, purpose, exampleType, summary, useCase, importance, code, tip) {
  return {
    category,
    title,
    difficulty,
    purpose,
    exampleType,
    summary,
    useCase,
    importance,
    code,
    tip
  };
}

